import{_ as n,C as t,o as i,c as o,a0 as a,E as r}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"part-6/ch34-mechanical-sympathy.md","filePath":"part-6/ch34-mechanical-sympathy.md"}'),l={name:"part-6/ch34-mechanical-sympathy.md"};function c(h,e,d,p,m,y){const s=t("VideoPlayer");return i(),o("div",null,[e[0]||(e[0]=a('<h2 id="chapter-34-mechanical-sympathy" tabindex="-1">Chapter 34: Mechanical Sympathy <a class="header-anchor" href="#chapter-34-mechanical-sympathy" aria-label="Permalink to &quot;Chapter 34: Mechanical Sympathy&quot;">​</a></h2><div class="slide-visualization-box no-print"><details><summary>📊 Slide Reference: <code>/slides/go-34-sympathy-slides.pdf</code></summary><div class="slide-iframe-container"><iframe src="/GO-Lang-Matt/slides/go-34-sympathy-slides.pdf" width="100%" height="450px" style="border:none;"></iframe></div></details></div>',2)),r(s,{videoId:"7QLoOd9HinY",chapter:"34"}),e[1]||(e[1]=a(`<p>Mechanical Sympathy means understanding the underlying hardware architecture (CPU cache hierarchies, memory layouts, pipelines) and writing software that cooperates with the machine rather than fighting it.</p><h3 id="the-memory-hierarchy-and-the-cpu-gap" tabindex="-1">The Memory Hierarchy and the CPU Gap <a class="header-anchor" href="#the-memory-hierarchy-and-the-cpu-gap" aria-label="Permalink to &quot;The Memory Hierarchy and the CPU Gap&quot;">​</a></h3><p>Since the 1980s, the speed of CPU arithmetic registers has grown exponentially, while main memory (DRAM) read latency has remained relatively flat.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Register Speed  : ~0.5ns (1 clock cycle)</span></span>
<span class="line"><span>L1 Cache Read   : ~1-2ns</span></span>
<span class="line"><span>L2 Cache Read   : ~4-5ns</span></span>
<span class="line"><span>L3 Cache Read   : ~15-20ns</span></span>
<span class="line"><span>Main DRAM Read  : ~60-100ns (Hundreds of cycles stalled waiting for data!)</span></span></code></pre></div><p>When a CPU needs a variable, it halts processing until the data is fetched from RAM. To hide this latency, modern processors use cache lines (typically 64-byte chunks) to pre-fetch contiguous memory.</p><hr><h3 id="locality-of-reference" tabindex="-1">Locality of Reference <a class="header-anchor" href="#locality-of-reference" aria-label="Permalink to &quot;Locality of Reference&quot;">​</a></h3><ol><li><strong>Temporal Locality:</strong> If a memory location is accessed, it is likely to be accessed again soon.</li><li><strong>Spatial Locality:</strong> If a memory location is accessed, nearby memory locations are likely to be accessed soon.</li></ol><h4 id="slice-vs-linked-list-layouts" tabindex="-1">Slice vs. Linked List Layouts <a class="header-anchor" href="#slice-vs-linked-list-layouts" aria-label="Permalink to &quot;Slice vs. Linked List Layouts&quot;">​</a></h4><ul><li><strong>Slice / Array (Contiguous Memory):</strong> Sequential reads of a slice yield perfect spatial locality. Reading <code>slice[0]</code> fetches the next few elements into L1 cache in a single hardware load.</li><li><strong>Linked List (Pointer Chasing):</strong> Linked list nodes are allocated dynamically on the heap. Traversing pointers (<code>node.Next</code>) requires jumping to arbitrary memory addresses, causing frequent cache misses.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Slice:       [ Val1 ][ Val2 ][ Val3 ][ Val4 ][ Val5 ]  (Contiguous Cache Line)</span></span>
<span class="line"><span>             ^-- Sequentially read</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Linked List: [ Val1 | Ptr ] ---&gt; [ Val2 | Ptr ] (Jumps to random heap locations)</span></span></code></pre></div><hr><h3 id="over-abstraction-and-method-dispatch-overhead" tabindex="-1">Over-Abstraction and Method Dispatch Overhead <a class="header-anchor" href="#over-abstraction-and-method-dispatch-overhead" aria-label="Permalink to &quot;Over-Abstraction and Method Dispatch Overhead&quot;">​</a></h3><p>Modern design patterns often advocate for deep layers of abstractions and short forwarding methods (methods that do nothing but delegate to another method).</p><p>In Go, interface method calls are <strong>dynamically dispatched</strong> via lookup tables (v-tables). This blocks compiler inlining optimizations. A function call that takes 100ns of overhead to do 1ns of addition is inefficient. A simpler structure with fewer layers performs better.</p><hr><h3 id="false-sharing" tabindex="-1">False Sharing <a class="header-anchor" href="#false-sharing" aria-label="Permalink to &quot;False Sharing&quot;">​</a></h3><p>CPUs manage cache consistency at the granularity of <strong>cache lines</strong>, not individual bytes or variables.</p><p>Suppose we have two independent variables <code>A</code> and <code>B</code> stored next to each other in memory, fitting inside the same 64-byte cache line.</p><ul><li>Core 1 updates <code>A</code> constantly.</li><li>Core 2 updates <code>B</code> constantly.</li></ul><p>Even though there is no logical race condition (the variables are distinct), the hardware must bounce ownership of the entire cache line back and forth between Core 1 and Core 2. This creates massive serialization overhead known as <strong>False Sharing</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Cache Line (64 Bytes) ]</span></span>
<span class="line"><span>|  Variable A (Core 1)  |  Variable B (Core 2)  |</span></span>
<span class="line"><span>+-----------------------+-----------------------+</span></span>
<span class="line"><span>   |                       |</span></span>
<span class="line"><span>   V                       V</span></span>
<span class="line"><span>  Core 1 Writes           Core 2 Writes</span></span>
<span class="line"><span>  (Invalidates Cache)     (Invalidates Cache)</span></span></code></pre></div><hr>`,23))])}const f=n(l,[["render",c]]);export{g as __pageData,f as default};
